noncompliant:
// Noncompliant - A single file with too many lines (e.g., >1000 lines)
// Example: A monolithic file containing multiple unrelated functions:

#include <stdio.h>
#include <stdlib.h>
// ... (imagine 950+ more lines with multiple unrelated functions)
void function1() { /* implementation */ }
void function2() { /* implementation */ }
void function3() { /* implementation */ }
// ... many more functions in a single file

compliant:
// Compliant - Split into smaller, focused files:

// math_operations.c (focused on mathematical operations)
#include "math_operations.h"
void add() { /* implementation */ }
void subtract() { /* implementation */ }

// string_utils.c (focused on string utilities)
#include "string_utils.h"
void trim() { /* implementation */ }
void concat() { /* implementation */ }

// main.c (focused on main program logic)
#include "math_operations.h"
#include "string_utils.h"
int main() { /* implementation */ }
